-- {"operators": "INNER_JOIN,AGGREGATE,WINDOW,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,OORDER,ORDER_LINE", "ducklake": true}
WITH order_value AS (SELECT OL_W_ID, OL_D_ID, OL_O_ID, SUM(OL_AMOUNT) AS amt FROM dl.ORDER_LINE GROUP BY OL_W_ID, OL_D_ID, OL_O_ID) SELECT w.W_ID, d.D_ID, c.C_ID, c.C_LAST, ov.amt, (ov.amt * (1 - c.C_DISCOUNT)) AS final_amt, SUM(ov.amt) OVER (PARTITION BY w.W_ID) AS w_total FROM dl.WAREHOUSE w JOIN dl.DISTRICT d ON w.W_ID = d.D_W_ID JOIN dl.CUSTOMER c ON d.D_W_ID = c.C_W_ID AND d.D_ID = c.C_D_ID JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID JOIN order_value ov ON o.O_W_ID = ov.OL_W_ID AND o.O_D_ID = ov.OL_D_ID AND o.O_ID = ov.OL_O_ID;
